import{_ as a,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Интеграция с Obsidian: Автосохранение планов | plannotator","description":"Изучите настройку интеграции Plannotator с Obsidian. Автоматическое сохранение одобренных планов в vault, включая генерацию frontmatter и тегов, поддержка настройки пути сохранения.","frontmatter":{"title":"Интеграция с Obsidian: Автосохранение планов | plannotator","sidebarTitle":"Автосохранение в Obsidian","subtitle":"Интеграция с Obsidian: Автосохранение планов | plannotator","description":"Изучите настройку интеграции Plannotator с Obsidian. Автоматическое сохранение одобренных планов в vault, включая генерацию frontmatter и тегов, поддержка настройки пути сохранения.","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"ru/backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"ru/backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),n={name:"ru/backnotprop/plannotator/advanced/obsidian-integration/index.md"};function r(l,t,s,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="интеграция-с-obsidian-автоматическое-сохранение-планов-в-хранилище-заметок" tabindex="-1">Интеграция с Obsidian: Автоматическое сохранение планов в хранилище заметок <a class="header-anchor" href="#интеграция-с-obsidian-автоматическое-сохранение-планов-в-хранилище-заметок" aria-label="Permalink to &quot;Интеграция с Obsidian: Автоматическое сохранение планов в хранилище заметок&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-обучения" tabindex="-1">Что вы сможете сделать после обучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-обучения" aria-label="Permalink to &quot;Что вы сможете сделать после обучения&quot;">​</a></h2><ul><li>Автоматически сохранять одобренные или отклонённые планы в Obsidian vault</li><li>Понимать механизм генерации frontmatter и тегов</li><li>Настраивать пути и папки для сохранения</li><li>Использовать backlink для построения графа знаний</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы проверяете планы, сгенерированные ИИ, в Plannotator, и после одобрения эти планы &quot;исчезают&quot;. Вы хотите сохранить эти ценные планы в Obsidian для последующего просмотра и поиска, но ручное копирование-вставка слишком утомительно, и форматирование нарушается.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li>Вы используете Obsidian в качестве инструмента управления знаниями</li><li>Вы хотите долгосрочно сохранять и просматривать планы реализации, сгенерированные ИИ</li><li>Вы хотите использовать graph view и систему тегов Obsidian для организации планов</li></ul><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><p>Функция интеграции Plannotator с Obsidian автоматически сохраняет содержимое плана в ваш Obsidian vault при одобрении или отклонении плана. Система будет:</p><ol><li><strong>Обнаруживать vaults</strong>: автоматически читать все vault из конфигурационного файла Obsidian</li><li><strong>Генерировать frontmatter</strong>: включая время создания, источник и теги</li><li><strong>Извлекать теги</strong>: автоматически извлекать теги из заголовка плана и языков кодовых блоков</li><li><strong>Добавлять backlink</strong>: вставлять ссылку <code>[[Plannotator Plans]]</code> для удобного построения графа знаний</li></ol><div class="info custom-block"><p class="custom-block-title">Что такое Obsidian?</p><p>Obsidian — это приложение для заметок с двунаправленными ссылками, ориентированное на локальное хранение, поддерживающее формат Markdown и визуализацию связей между заметками через graph view.</p></div><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><p>Убедитесь, что Obsidian установлен и настроен. Plannotator автоматически обнаружит vaults в системе, но для использования этой функции необходимо иметь хотя бы один vault.</p><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-откроите-панель-настроек" tabindex="-1">Шаг 1: Откройте панель настроек <a class="header-anchor" href="#шаг-1-откроите-панель-настроек" aria-label="Permalink to &quot;Шаг 1: Откройте панель настроек&quot;">​</a></h3><p>В интерфейсе Plannotator нажмите на иконку шестерёнки в правом верхнем углу, чтобы открыть панель настроек.</p><p>Вы должны увидеть диалоговое окно настроек с несколькими параметрами конфигурации.</p><h3 id="шаг-2-включите-интеграцию-с-obsidian" tabindex="-1">Шаг 2: Включите интеграцию с Obsidian <a class="header-anchor" href="#шаг-2-включите-интеграцию-с-obsidian" aria-label="Permalink to &quot;Шаг 2: Включите интеграцию с Obsidian&quot;">​</a></h3><p>В панели настроек найдите раздел &quot;Obsidian Integration&quot; и нажмите переключатель, чтобы включить эту функцию.</p><p>После включения Plannotator автоматически обнаружит Obsidian vaults в системе.</p><p>Вы должны увидеть в выпадающем меню список обнаруженных vaults (например, <code>My Vault</code>, <code>Work Notes</code>).</p><h3 id="шаг-3-выберите-vault-и-папку" tabindex="-1">Шаг 3: Выберите vault и папку <a class="header-anchor" href="#шаг-3-выберите-vault-и-папку" aria-label="Permalink to &quot;Шаг 3: Выберите vault и папку&quot;">​</a></h3><p>Из выпадающего меню выберите vault, в который вы хотите сохранять планы. Если vault не обнаружен, вы можете:</p><ol><li>Выбрать опцию &quot;Custom path...&quot;</li><li>Ввести полный путь к vault в текстовое поле</li></ol><p>Затем в поле &quot;Folder&quot; установите имя папки для сохранения (по умолчанию <code>plannotator</code>).</p><p>Вы должны увидеть предварительный просмотр пути ниже, показывающий, где будут сохранены планы.</p><h3 id="шаг-4-одобрите-или-отклоните-план" tabindex="-1">Шаг 4: Одобрите или отклоните план <a class="header-anchor" href="#шаг-4-одобрите-или-отклоните-план" aria-label="Permalink to &quot;Шаг 4: Одобрите или отклоните план&quot;">​</a></h3><p>После завершения настройки проверяйте планы, сгенерированные ИИ, как обычно. Когда вы нажимаете &quot;Approve&quot; или &quot;Send Feedback&quot;, план автоматически сохраняется в настроенный vault.</p><p>Вы должны увидеть в Obsidian новый созданный файл с именем в формате <code>Title - Jan 2, 2026 2-30pm.md</code>.</p><h3 id="шаг-5-просмотрите-сохраненныи-фаил" tabindex="-1">Шаг 5: Просмотрите сохранённый файл <a class="header-anchor" href="#шаг-5-просмотрите-сохраненныи-фаил" aria-label="Permalink to &quot;Шаг 5: Просмотрите сохранённый файл&quot;">​</a></h3><p>Откройте сохранённый файл в Obsidian, вы увидите следующее содержимое:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>Вы должны заметить, что в верхней части файла есть YAML frontmatter, содержащий время создания, источник и теги.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] В панели настроек Obsidian Integration включена</li><li>[ ] Выбран vault (или введён пользовательский путь)</li><li>[ ] Установлено имя папки</li><li>[ ] После одобрения или отклонения плана в Obsidian появляется новый файл</li><li>[ ] Файл содержит frontmatter и backlink <code>[[Plannotator Plans]]</code></li></ul><h2 id="подробности-о-frontmatter-и-тегах" tabindex="-1">Подробности о Frontmatter и тегах <a class="header-anchor" href="#подробности-о-frontmatter-и-тегах" aria-label="Permalink to &quot;Подробности о Frontmatter и тегах&quot;">​</a></h2><h3 id="структура-frontmatter" tabindex="-1">Структура Frontmatter <a class="header-anchor" href="#структура-frontmatter" aria-label="Permalink to &quot;Структура Frontmatter&quot;">​</a></h3><p>Каждый сохранённый план содержит следующие поля frontmatter:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Пример значения</th><th>Описание</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>Временная метка создания в формате ISO 8601</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>Фиксированное значение, идентифицирующее источник</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>Массив автоматически извлечённых тегов</td></tr></tbody></table><h3 id="правила-генерации-тегов" tabindex="-1">Правила генерации тегов <a class="header-anchor" href="#правила-генерации-тегов" aria-label="Permalink to &quot;Правила генерации тегов&quot;">​</a></h3><p>Plannotator использует следующие правила для автоматического извлечения тегов:</p><ol><li><strong>Тег по умолчанию</strong>: всегда включает тег <code>plannotator</code></li><li><strong>Тег имени проекта</strong>: автоматически извлекается из имени git-репозитория или имени каталога</li><li><strong>Ключевые слова заголовка</strong>: извлекаются значимые слова из первого заголовка H1 (исключая общие стоп-слова)</li><li><strong>Теги языков кода</strong>: извлекаются из идентификаторов языков кодовых блоков (например, <code>typescript</code>, <code>sql</code>). Общие языки конфигурации (такие как <code>json</code>, <code>yaml</code>, <code>markdown</code>) автоматически фильтруются.</li></ol><p>Список стоп-слов (не будут использоваться как теги):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>Ограничение количества тегов: максимум 7 тегов, упорядоченных по порядку извлечения.</p><h3 id="формат-имени-фаила" tabindex="-1">Формат имени файла <a class="header-anchor" href="#формат-имени-фаила" aria-label="Permalink to &quot;Формат имени файла&quot;">​</a></h3><p>Имя файла использует легко читаемый формат: <code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>Часть</th><th>Пример</th><th>Описание</th></tr></thead><tbody><tr><td>Заголовок</td><td><code>User Authentication</code></td><td>Извлечён из H1, ограничен 50 символами</td></tr><tr><td>Дата</td><td><code>Jan 2, 2026</code></td><td>Текущая дата</td></tr><tr><td>Время</td><td><code>2-30pm</code></td><td>Текущее время (12-часовой формат)</td></tr></tbody></table><h3 id="механизм-backlink" tabindex="-1">Механизм Backlink <a class="header-anchor" href="#механизм-backlink" aria-label="Permalink to &quot;Механизм Backlink&quot;">​</a></h3><p>В нижней части каждого файла плана вставляется ссылка <code>[[Plannotator Plans]]</code>. Назначение этого backlink:</p><ul><li><strong>Связь в графе знаний</strong>: в graph view Obsidian все планы связаны с одним узлом</li><li><strong>Быстрая навигация</strong>: нажатие на <code>[[Plannotator Plans]]</code> позволяет создать индексную страницу, объединяющую все сохранённые планы</li><li><strong>Двунаправленные ссылки</strong>: использование обратных ссылок на индексной странице для просмотра всех планов</li></ul><h2 id="кроссплатформенная-поддержка" tabindex="-1">Кроссплатформенная поддержка <a class="header-anchor" href="#кроссплатформенная-поддержка" aria-label="Permalink to &quot;Кроссплатформенная поддержка&quot;">​</a></h2><p>Plannotator автоматически определяет расположение конфигурационного файла Obsidian для разных операционных систем:</p><table tabindex="0"><thead><tr><th>Операционная система</th><th>Путь к конфигурационному файлу</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>Если автоматическое обнаружение не удалось, вы можете вручную ввести путь к vault.</p><h2 id="предупреждения-о-проблемах" tabindex="-1">Предупреждения о проблемах <a class="header-anchor" href="#предупреждения-о-проблемах" aria-label="Permalink to &quot;Предупреждения о проблемах&quot;">​</a></h2><h3 id="проблема-1-vaults-не-обнаружены" tabindex="-1">Проблема 1: Vaults не обнаружены <a class="header-anchor" href="#проблема-1-vaults-не-обнаружены" aria-label="Permalink to &quot;Проблема 1: Vaults не обнаружены&quot;">​</a></h3><p><strong>Симптом</strong>: выпадающее меню показывает &quot;Detecting...&quot;, но результатов нет</p><p><strong>Причина</strong>: конфигурационный файл Obsidian не существует или имеет неправильный формат</p><p><strong>Решение</strong>:</p><ol><li>Убедитесь, что Obsidian установлен и открывался хотя бы один раз</li><li>Проверьте, существует ли конфигурационный файл (см. таблицу путей выше)</li><li>Используйте &quot;Custom path...&quot; для ручного ввода пути к vault</li></ol><h3 id="проблема-2-фаил-не-наиден-после-сохранения" tabindex="-1">Проблема 2: Файл не найден после сохранения <a class="header-anchor" href="#проблема-2-фаил-не-наиден-после-сохранения" aria-label="Permalink to &quot;Проблема 2: Файл не найден после сохранения&quot;">​</a></h3><p><strong>Симптом</strong>: после одобрения плана в Obsidian нет нового файла</p><p><strong>Причина</strong>: неправильный путь к vault или Obsidian не обновлён</p><p><strong>Решение</strong>:</p><ol><li>Проверьте, правильный ли предварительный просмотр пути в панели настроек</li><li>В Obsidian нажмите &quot;Reload vault&quot; или нажмите <code>Cmd+R</code> (macOS) / <code>Ctrl+R</code> (Windows/Linux)</li><li>Проверьте, выбран ли правильный vault</li></ol><h3 id="проблема-3-имя-фаила-содержит-специальные-символы" tabindex="-1">Проблема 3: Имя файла содержит специальные символы <a class="header-anchor" href="#проблема-3-имя-фаила-содержит-специальные-символы" aria-label="Permalink to &quot;Проблема 3: Имя файла содержит специальные символы&quot;">​</a></h3><p><strong>Симптом</strong>: в имени файла появляются <code>_</code> или другие заменяющие символы</p><p><strong>Причина</strong>: заголовок содержит символы, не поддерживаемые файловой системой (<code>&lt; &gt; : &quot; / \\ | ? *</code>)</p><p><strong>Решение</strong>: это ожидаемое поведение, Plannotator автоматически заменяет эти символы, чтобы избежать ошибок файловой системы.</p><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Функция интеграции с Obsidian обеспечивает бесшовное соединение вашего процесса проверки планов с управлением знаниями:</p><ul><li>✅ Автоматическое сохранение одобренных или отклонённых планов</li><li>✅ Интеллектуальное извлечение тегов для удобного последующего поиска</li><li>✅ Генерация frontmatter, унифицированный формат метаданных</li><li>✅ Добавление backlink, построение графа знаний</li></ul><p>После однократной настройки каждая проверка будет автоматически архивироваться, больше не нужно вручную копировать и вставлять.</p><h2 id="предварительныи-просмотр-следующего-урока" tabindex="-1">Предварительный просмотр следующего урока <a class="header-anchor" href="#предварительныи-просмотр-следующего-урока" aria-label="Permalink to &quot;Предварительный просмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../bear-integration/">Интеграцию с Bear</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как сохранять планы в приложение для заметок Bear</li><li>Различия между интеграцией Bear и интеграцией Obsidian</li><li>Использование x-callback-url для автоматического создания заметок</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Обнаружение Obsidian vaults</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>Сохранение плана в Obsidian</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>Извлечение тегов</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Генерация frontmatter</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>Генерация имени файла</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Хранение настроек Obsidian</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Компонент Settings UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>Ключевые функции</strong>:</p><ul><li><code>detectObsidianVaults()</code>: читает конфигурационный файл Obsidian, возвращает список доступных путей к vault</li><li><code>saveToObsidian(config)</code>: сохраняет план в указанный vault, включая frontmatter и backlink</li><li><code>extractTags(markdown)</code>: извлекает теги из содержимого плана (ключевые слова заголовка, языки кода, имя проекта)</li><li><code>generateFrontmatter(tags)</code>: генерирует строку YAML frontmatter</li><li><code>generateFilename(markdown)</code>: генерирует читаемое имя файла</li></ul><p><strong>Бизнес-правила</strong>:</p><ul><li>Максимум 7 тегов (L73)</li><li>Имя файла ограничено 50 символами (L102)</li><li>Поддержка обнаружения путей к конфигурационным файлам на разных платформах (L141-149)</li><li>Автоматическое создание несуществующих папок (L208)</li></ul></details>`,79)])])}const u=a(n,[["render",r]]);export{b as __pageData,u as default};
